
<template>
<view>
<mescroll-uni @init="mescrollInit" :up="upOption" :down="downOption" @down="downCallback" @up="upCallback" @scroll="scrollChange">
	<view class="content">
		<view class="container" :style='{"minHeight":"100%","width":"100%","padding":"0","position":"relative","background":"#F6F7F9","height":"auto"}'>
			<swiper :style='{"width":"100%","background":"#fff","height":"360rpx"}' class="swiper" :indicator-dots='true' :autoplay='false' :circular='true' indicator-active-color='#000000' indicator-color='rgba(0, 0, 0, .3)' :duration='500' :interval='5000' :vertical='false'>
				<swiper-item :style='{"width":"100%","background":"#fff","height":"360rpx"}' v-for="(swiper,index) in swiperList" :key="index">
					<img :style='{"width":"100%","objectFit":"cover","display":"block","height":"360rpx"}' v-if="swiper.substring(0,4)=='http'" :src="swiper" @tap="imgView(swiper)">
					<img :style='{"width":"100%","objectFit":"cover","display":"block","height":"360rpx"}' v-else :src="baseUrl+swiper" @tap="imgView(baseUrl+swiper)">
				</swiper-item>
			</swiper>
			<view :style='{"padding":"24rpx","borderRadius":"30rpx","flexWrap":"wrap","background":"#fff","display":"flex","width":"100%","height":"auto"}' class="detail-content">

				<view :style='{"padding":"0","margin":"0 0 0px 0","borderColor":"#cccccc","borderWidth":"0","display":"flex","width":"100%","borderStyle":"solid","height":"auto"}' class="detail-list-item title">
					<view :style='{"padding":"0 20rpx 0 0","whiteSpace":"nowrap","color":"#000","textAlign":"right","width":"auto","lineHeight":"48rpx","fontSize":"28rpx","fontWeight":"bold"}' class="lable">еІУеРНпЉЪ</view>
					<view :style='{"padding":"0px","margin":"0px","lineHeight":"48rpx","fontSize":"28rpx","color":"#666"}' class="text" >{{detail.xingming}}</view>
				</view>

				<view class="detail-list-item" :style='{"padding":"0","margin":"0 0 0px 0","borderColor":"#cccccc","borderWidth":"0","display":"flex","width":"100%","borderStyle":"solid","height":"auto"}'>
					<view class="lable" :style='{"padding":"0 20rpx 0 0","whiteSpace":"nowrap","color":"#000","textAlign":"right","width":"auto","lineHeight":"48rpx","fontSize":"28rpx","fontWeight":"bold"}'>е≠¶еПЈпЉЪ</view>
					<view class="text" :style='{"padding":"0px","margin":"0px","lineHeight":"48rpx","fontSize":"28rpx","color":"#666"}' >{{detail.xuehao}}</view>
				</view>
				<view class="detail-list-item" :style='{"padding":"0","margin":"0 0 0px 0","borderColor":"#cccccc","borderWidth":"0","display":"flex","width":"100%","borderStyle":"solid","height":"auto"}'>
					<view class="lable" :style='{"padding":"0 20rpx 0 0","whiteSpace":"nowrap","color":"#000","textAlign":"right","width":"auto","lineHeight":"48rpx","fontSize":"28rpx","fontWeight":"bold"}'>жАІеИЂпЉЪ</view>
					<view class="text" :style='{"padding":"0px","margin":"0px","lineHeight":"48rpx","fontSize":"28rpx","color":"#666"}' >{{detail.xingbie}}</view>
				</view>
				<view class="detail-list-item" :style='{"padding":"0","margin":"0 0 0px 0","borderColor":"#cccccc","borderWidth":"0","display":"flex","width":"100%","borderStyle":"solid","height":"auto"}'>
					<view class="lable" :style='{"padding":"0 20rpx 0 0","whiteSpace":"nowrap","color":"#000","textAlign":"right","width":"auto","lineHeight":"48rpx","fontSize":"28rpx","fontWeight":"bold"}'>йВЃзЃ±пЉЪ</view>
					<view class="text" :style='{"padding":"0px","margin":"0px","lineHeight":"48rpx","fontSize":"28rpx","color":"#666"}' >{{detail.youxiang}}</view>
				</view>
				<view class="detail-list-item" :style='{"padding":"0","margin":"0 0 0px 0","borderColor":"#cccccc","borderWidth":"0","display":"flex","width":"100%","borderStyle":"solid","height":"auto"}'>
					<view class="lable" :style='{"padding":"0 20rpx 0 0","whiteSpace":"nowrap","color":"#000","textAlign":"right","width":"auto","lineHeight":"48rpx","fontSize":"28rpx","fontWeight":"bold"}'>жЙЛжЬЇеПЈпЉЪ</view>
					<view class="text" :style='{"padding":"0px","margin":"0px","lineHeight":"48rpx","fontSize":"28rpx","color":"#666"}' style="text-decoration: underline" @tap="callClick(detail.mobile)" >{{detail.mobile}}</view>
				</view>








				<view class="bottom-content bg-white tabbar border shop" :style='{"padding":"20rpx 10rpx","margin":"20rpx 0","borderRadius":"20rpx","flexWrap":"wrap","background":"#EDEDED","display":"flex","width":"100%","height":"auto","order":"1"}'>

				</view>
			</view>
		</view>
	</view>
</mescroll-uni>
</view>
</template>

<script>
	export default {
		data() {
			return {
				btnColor: ['#409eff','#67c23a','#909399','#e6a23c','#f56c6c','#356c6c','#351c6c','#f093a9','#a7c23a','#104eff','#10441f','#a21233','#503319'],
				id: '',
				userid: '',
				detail: {},
				swiperList: [],
				commentList: [],
				mescroll: null, //mescrollеЃЮдЊЛеѓєи±°
				downOption: {
					auto: false //жШѓеР¶еЬ®еИЭеІЛеМЦеРО,иЗ™еК®жЙІи°МдЄЛжЛЙеЫЮи∞Гcallback; йїШиЃ§true
				},
				upOption: {
					noMoreSize: 3, //е¶ВжЮЬеИЧи°®еЈ≤жЧ†жХ∞жНЃ,еПѓиЃЊзљЃеИЧи°®зЪДжАїжХ∞йЗПи¶Бе§ІдЇОеНКй°µжЙНжШЊз§ЇжЧ†жЫіе§ЪжХ∞жНЃ;йБњеЕНеИЧи°®жХ∞жНЃињЗе∞С(жѓФе¶ВеП™жЬЙдЄАжЭ°жХ∞жНЃ),жШЊз§ЇжЧ†жЫіе§ЪжХ∞жНЃдЉЪдЄНе•љзЬЛ; йїШиЃ§5
					textNoMore: '~ ж≤°жЬЙжЫіе§ЪдЇЖ ~',
					onScroll: true,
					toTop: true
				},
				hasNext: true,
				user: {},
				count: 0,
				timer: null,
				title:'',
				scrollTop: 0,
			}
		},
		components: {
		},
		computed: {
			baseUrl() {
				return this.$base.url;
			},
			username() {
				return uni.getStorageSync("nickname")
			},
		},
		async onLoad(options) {
			// #ifdef APP-PLUS
			let page = getCurrentPages()
			this.href = this.baseUrl + 'front/h5/#/' + page[page.length - 1].route
			// #endif
			let table = uni.getStorageSync("nowTable");
			// иОЈеПЦзФ®жИЈдњ°жБѓ
			let res = await this.$api.session(table);
			this.user = res.data;
			this.id = options.id;
			if(options.userid) {
				this.userid = options.userid;
			}
			// жЄ≤жЯУжХ∞жНЃ
			this.init();
		},
		// #ifdef MP-WEIXIN
		onShareAppMessage(){
			var obj = {
				title: this.title,
				imageUrl: this.swiperList[0]?this.baseUrl + this.swiperList[0]: ''
			}
			return obj
		},
		// #endif
		onUnload() {
			if(this.timer) {
				clearInterval(this.timer);
			}
		},
		async onShow(options) {
			let table = uni.getStorageSync("nowTable");
			// иОЈеПЦзФ®жИЈдњ°жБѓ
			let res = await this.$api.session(table);
			this.user = res.data;
			this.btnColor = this.btnColor.sort(()=> {
				return (0.5-Math.random());
			});
			let crossCleanType = uni.getStorageSync('crossCleanType')
			if(crossCleanType) {
				uni.removeStorageSync('crossCleanType')
				res = await this.$api.info('xuesheng', this.id);
				let reg=new RegExp('http://localhost:8081/code/upload','g')//gдї£и°®еЕ®йГ®
				this.detail = res.data;
				this.title = this.detail.xingming
			}
		},
		destroyed: function() {
			//window.clearInterval(this.inter);
		},
		methods: {
			scrollChange(e){
				this.scrollTop = e.scrollTop
			},
			scrollTopClick(){
				uni.pageScrollTo({
					scrollTop: 0
				})
			},
			imgView(url){
				let arr = []
				for(let x in this.swiperList){
					arr.push(this.swiperList[x].substr(0,4)=='http'?this.swiperList[x]:this.baseUrl + this.swiperList[x])
				}
				uni.previewImage({
					current: url,
					urls: arr
				})
			},
			// жЛ®жЙУзФµиѓЭ
			callClick(row){
				uni.makePhoneCall({
					phoneNumber: row
				})
			},
			// жФѓдїШ
			onPayTap(){
				let that = this
				if(!this.user){
					this.$utils.msg("иѓЈеЕИзЩїељХ")
					setTimeout(()=>{
						that.$utils.jump('../login/login')
					},1500)
					return false
				}
				uni.setStorageSync('paytable','xuesheng');
				uni.setStorageSync('payObject',this.detail);
				this.$utils.jump('../pay-confirm/pay-confirm?type=1')
			},
			onDetailTap(item) {
				uni.setStorageSync("useridTag",this.userid);
				this.$utils.jump(`./detail?id=${item.id}&userid=`+this.userid)
			},
			// иЈ®и°®
			async onAcrossTap(tableName,crossOptAudit,crossOptPay,statusColumnName,tips,statusColumnValue,type=1){
				let that = this
				if(!this.user){
					this.$utils.msg("иѓЈеЕИзЩїељХ")
					setTimeout(()=>{
						that.$utils.jump('../login/login')
					},1500)
					return false
				}
				uni.setStorageSync('crossTable','xuesheng');
				uni.setStorageSync(`crossObj`, this.detail);
				uni.setStorageSync(`statusColumnName`, statusColumnName);
				uni.setStorageSync(`statusColumnValue`, statusColumnValue);
				uni.setStorageSync(`tips`, tips);
				if(statusColumnName!=''&&!statusColumnName.startsWith("[")) {
					var obj = uni.getStorageSync('crossObj');
					for (var o in obj){
						if(o==statusColumnName && obj[o]==statusColumnValue){
							this.$utils.msg(tips);
							return
						}
					}
				}
				this.$utils.jump(`../${tableName}/add-or-update?cross=true`);
			},
			// иОЈеПЦиѓ¶жГЕ
			async init(type=1){
				if(this.timer) {
					clearInterval(this.timer);
				}
				let res = await this.$api.info('xuesheng', this.id);
				let reg=new RegExp('http://localhost:8081/code/upload','g')//gдї£и°®еЕ®йГ®
				this.detail = res.data;

				this.title = this.detail.xingming




				// иљЃжТ≠еЫЊзЙЗ
				this.swiperList = this.detail.touxiang ? this.detail.touxiang.split(",") : [];
				





				if(type==2){
					this.detail.discussnum++
					await this.$api.update('xuesheng',this.detail)
				}
			},
			// mescrollзїДдїґеИЭеІЛеМЦзЪДеЫЮи∞Г,еПѓиОЈеПЦеИ∞mescrollеѓєи±°
			mescrollInit(mescroll) {
				this.mescroll = mescroll;
			},

			/*дЄЛжЛЙеИЈжЦ∞зЪДеЫЮи∞Г */
			downCallback(mescroll) {
				this.hasNext = true
				mescroll.resetUpScroll()
			},

			/*дЄКжЛЙеК†иљљзЪДеЫЮи∞Г: mescrollжРЇеЄ¶pageзЪДеПВжХ∞, еЕґдЄ≠num:ељУеЙНй°µ дїО1еЉАеІЛ, size:жѓПй°µжХ∞жНЃжЭ°жХ∞,йїШиЃ§10 */
			async upCallback(mescroll) {
				mescroll.endSuccess(mescroll.size, this.hasNext);

			},



			onChatTap() {
				this.$utils.jump('../chat/chat')
			},
			// дЄЛиљљ
			download(url ){
				if(!url){
					return false
				}
				let _this = this;
				url=_this.$base.url +  url;
				uni.downloadFile({
					url: url,
					success: (res) => {
						if (res.statusCode === 200) {
							_this.$utils.msg('дЄЛиљљжИРеКЯ');
							// #ifdef H5
							 window.open(url);
							// #endif
							// #ifndef H5
							uni.saveFile({
								tempFilePath: res.tempFilePath, //дЄіжЧґиЈѓеЊД
								success: function(obj) {
									uni.showToast({
										icon: 'success',
										mask: true,
										title: 'дЄЛиљљжИРеКЯ' , 
										duration: 2000,
									});
									setTimeout(() => {
										console.log('obj.savedFilePath',obj.savedFilePath);
										var filePath = obj.savedFilePath;
										uni.openDocument({ //жЦ∞еЉАй°µйЭҐжЙУеЉАжЦЗж°£пЉМжФѓжМБж†ЉеЉПпЉЪdoc, xls, ppt, pdf, docx, xlsx, pptxгАВ
											filePath: filePath,
											showMenu: true,
											success: function(res) {
												console.log('жЙУеЉАжЦЗж°£жИРеКЯ');
											}
										});
									}, 2000)
								}
							});
							// #endif
						}
					}
				});
			},
			//
			onCartTabTap() {
				this.$utils.tab('../shop-cart/shop-cart')
			},

		}
	}
</script>

<style lang="scss">
	page {
	  --animate-duration: 1s;
	  --animate-delay: 1s;
	  --animate-repeat: 1;
	}
	
	.content {
		min-height: calc(100vh - 44px);
		box-sizing: border-box;
	}
	
	.seat-list {
		display: flex;
		align-items: center;
		flex-wrap: wrap;
		background: #FFFFFF;
		margin: 20upx;
		border-radius: 20upx;
		padding: 20upx;
		font-size: 30upx;
		.seat-item {
			width: 33.33%;
			display: flex;
			align-items: center;
			flex-direction: column;
			margin-bottom: 20upx;
	
			.seat-icon {
				width: 50upx;
				height: 50upx;
				margin-bottom: 10upx;
			}
		}
	}
	
	audio {
		display: flex;
		flex-direction: column;
	}
	
	.audio .uni-audio-default {
		width: inherit !important;
	}
	

</style>
